import { SAVE_COMMENT } from './types';

export function saveComment(comment) {
    return {
        type: SAVE_COMMENT,
        payload: comment
    };
}

export function fetchComments() {
    const response = fetch('http://jsonplaceholder.typicode.com/comments')
        .then(res => res.json());
    return {
        type: FETCH_COMMENTS,
        payload: response
    }
}
